class Car:
    def __init__(self, make, model, year):
        self.make = make
        self.model = model
        self.year = year

    def car_info(self):
        return f'{self.year} {self.make} {self.model}'

my_car = Car('Toyota', 'Corolla', 2020)
print(my_car.car_info())

class Car:
    def __init__(self, make, model, year):
        self.make = make
        self.model = model
        self.year = year

    def update_model(self, new_model):
        self.model = new_model

my_car = Car('Toyota', 'Corolla', 2020)
my_car.update_model('Camry')
print(my_car.model)
